define("theme_boost_union/megamenu",[],(function(){"use strict";const BODY_OPEN_CLASS="theme-megamenu-open";let lastFocus=null;const getFocusable=function(container){const selector='a[href], button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])';return Array.prototype.slice.call(container.querySelectorAll(selector)).filter((function(node){return null!==node.offsetParent}))};const openOverlay=function(overlay,trigger){lastFocus=document.activeElement;overlay.hidden=!1;void overlay.offsetWidth;overlay.classList.add("is-open");document.documentElement.classList.add(BODY_OPEN_CLASS);if(trigger){trigger.setAttribute("aria-expanded","true")}const focusable=getFocusable(overlay);if(focusable.length){focusable[0].focus()}};const closeOverlay=function(overlay,trigger){overlay.classList.remove("is-open");document.documentElement.classList.remove(BODY_OPEN_CLASS);if(trigger){trigger.setAttribute("aria-expanded","false")}const reduced=window.matchMedia("(prefers-reduced-motion: reduce)").matches;if(reduced){overlay.hidden=!0}else{window.setTimeout((function(){if(!overlay.classList.contains("is-open")){overlay.hidden=!0}}),250)}if(lastFocus){lastFocus.focus()}};const init=function(){const overlay=document.getElementById("theme_boost_union-megamenu"),trigger=document.getElementById("theme_boost_union-megamenu-trigger"),closebtn=document.getElementById("theme_boost_union-megamenu-close");if(!overlay||!trigger){return}trigger.addEventListener("click",(function(){openOverlay(overlay,trigger)}));if(closebtn){closebtn.addEventListener("click",(function(){closeOverlay(overlay,trigger)}))}overlay.addEventListener("mousedown",(function(e){if(e.target===overlay){closeOverlay(overlay,trigger)}}));overlay.addEventListener("click",(function(e){if(e.target.closest('[data-region="popover-region-messages"]')){closeOverlay(overlay,trigger)}}));overlay.addEventListener("keydown",(function(e){if("Tab"!==e.key){return}const focusable=getFocusable(overlay);if(!focusable.length){return}const first=focusable[0],last=focusable[focusable.length-1];if(e.shiftKey&&document.activeElement===first){e.preventDefault();last.focus()}else if(!e.shiftKey&&document.activeElement===last){e.preventDefault();first.focus()}}));document.addEventListener("keydown",(function(e){if("Escape"===e.key&&!overlay.hidden){closeOverlay(overlay,trigger)}}))};return{init:init}}));
